Bash(node -e "
const { signal, computed, effect, setCurrentSub } = require\('alien-signals'\);

// Simulate what action-wrapping a computed getter would do
const count = signal\(5\);
const doubled = computed\(\(\) => count\(\) * 2\);

// Normal: computed inside effect tracks correctly
let tracked = 0;
effect\(\(\) => { doubled\(\); tracked++; }\);
console.log\('tracked after setup:', tracked\); // 1
count\(10\);
console.log\('tracked after change:', tracked\); // 2

// Now simulate action-wrapped computed call inside an effect
let actionTracked = 0;
const wrappedDoubled = \(\) => {
  const prev = setCurrentSub\(undefined\);
  try { return doubled\(\); }
  finally { setCurrentSub\(prev\); }
};

effect\(\(\) => { wrappedDoubled\(\); actionTracked++; }\);
console.log\('actionTracked after setup:', actionTracked\); // 1
count\(20\);
console.log\('actionTracked after change:', actionTracked\); // should be 1 \(broken tracking!\)
console.log\('BUT tracked \(unwrapped\) still works:', tracked\); // 3
")

