// Simulate React StrictMode lifecycle with useState + useEffect cleanup
// Mount 1:  useState\(\(\) => factory\(\)\) creates model
// Effect 1: registers cleanup
// Unmount 1: cleanup runs → dispose\(\)
// Mount 2:  useState returns SAME value \(React reuses state\)
// Effect 2: registers cleanup again — but model is already disposed

class FakeModel {
  constructor\(\) { this.alive = true; console.log\('Model created, alive:', this.alive\); }
  dispose\(\) { this.alive = false; console.log\('Model disposed, alive:', this.alive\); }
}

// Simulate
const state = { current: null };

// Mount 1
if \(!state.current\) state.current = new FakeModel\(\);
console.log\('Mount 1 - model alive:', state.current.alive\);

// Unmount 1 \(StrictMode\)
state.current.dispose\(\);
console.log\('Unmount 1 - model alive:', state.current.alive\);

// Mount 2 \(StrictMode remount - useState returns same ref\)
console.log\('Mount 2 - model alive:', state.current.alive, '← BUG: using disposed model'\);
")

